class Point():
    def __init__(self, x, y):
        self.x = float(x)
        self.y = float(y)
    def distance(self, other):
        return other.x - self.x, other.y - self.y
    def __repr__(self):
        return "Point({}, {})".format(self.x, self.y)
    def __str__(self):
        return "({}, {})".format(self.x, self.y)

